import{_ as e,c as a,o as n,ag as o}from"./chunks/framework.DD2hp6gW.js";const i="/assets/settings-cart-quantity-percentage.B3Lf03J4.png",s="/assets/settings-cart-quantity-fixed.CiQl8jHp.png",r="/assets/settings-cart-bogo-format.zBg6TEVn.png",c="/assets/settings-cart-stacking-coupons.BOiPyjUr.png",d="/assets/settings-cart-stacking-campaigns.C1zeoMVN.png",b=JSON.parse('{"title":"Cart Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/cart-settings.md","filePath":"settings/cart-settings.md","lastUpdated":null}'),l={name:"settings/cart-settings.md"};function h(p,t,g,u,m,f){return n(),a("div",null,t[0]||(t[0]=[o('<h1 id="cart-settings" tabindex="-1">Cart Settings <a class="header-anchor" href="#cart-settings" aria-label="Permalink to &quot;Cart Settings&quot;">​</a></h1><p>The <strong>Cart Settings</strong> tab manages how discounts are communicated and calculated within the WooCommerce cart and checkout flow.</p><h2 id="cart-page-display" tabindex="-1">Cart Page Display <a class="header-anchor" href="#cart-page-display" aria-label="Permalink to &quot;Cart Page Display&quot;">​</a></h2><h3 id="message-formats" tabindex="-1">Message Formats <a class="header-anchor" href="#message-formats" aria-label="Permalink to &quot;Message Formats&quot;">​</a></h3><p>Configure the upsell and discount messages that appear in the cart for different campaign types.</p><h4 id="quantity-discount-percentage" tabindex="-1">Quantity Discount (Percentage) <a class="header-anchor" href="#quantity-discount-percentage" aria-label="Permalink to &quot;Quantity Discount (Percentage)&quot;">​</a></h4><p><img src="'+i+'" alt="Cart Quantity Percentage Format"></p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>{remaining_quantity_for_next_offer}</code></td><td>Items needed to reach the next tier</td></tr><tr><td><code>{percentage_off}</code></td><td>Discount percentage at next tier</td></tr></tbody></table><p><strong>Example:</strong> <code>Add {remaining_quantity_for_next_offer} more and get {percentage_off}% off</code></p><h4 id="quantity-discount-fixed" tabindex="-1">Quantity Discount (Fixed) <a class="header-anchor" href="#quantity-discount-fixed" aria-label="Permalink to &quot;Quantity Discount (Fixed)&quot;">​</a></h4><p><img src="'+s+'" alt="Cart Quantity Fixed Format"></p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>{remaining_quantity_for_next_offer}</code></td><td>Items needed to reach the next tier</td></tr><tr><td><code>{amount_off}</code></td><td>Fixed discount amount at next tier</td></tr></tbody></table><p><strong>Example:</strong> <code>Add {remaining_quantity_for_next_offer} more and get {amount_off} off per it</code></p><h4 id="bogo-discount" tabindex="-1">BOGO Discount <a class="header-anchor" href="#bogo-discount" aria-label="Permalink to &quot;BOGO Discount&quot;">​</a></h4><p><img src="'+r+'" alt="Cart BOGO Format"></p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>{title}</code></td><td>Campaign title</td></tr><tr><td><code>{buy_product_name}</code></td><td>Name of the qualifying product</td></tr></tbody></table><p><strong>Example:</strong> <code>{title} discount applied.</code></p><hr><h2 id="cart-discount-options" tabindex="-1">Cart Discount Options <a class="header-anchor" href="#cart-discount-options" aria-label="Permalink to &quot;Cart Discount Options&quot;">​</a></h2><h3 id="allow-stacking-with-woocommerce-coupons" tabindex="-1">Allow Stacking with WooCommerce Coupons <a class="header-anchor" href="#allow-stacking-with-woocommerce-coupons" aria-label="Permalink to &quot;Allow Stacking with WooCommerce Coupons&quot;">​</a></h3><p><img src="'+c+'" alt="Stacking with Coupons"></p><ul><li><strong>Checked:</strong> Campaign discounts can be combined with standard WooCommerce coupons.</li><li><strong>Unchecked:</strong> The two discount systems are mutually exclusive.</li></ul><h3 id="allow-stacking-with-other-discount-campaigns" tabindex="-1">Allow Stacking with Other Discount Campaigns <a class="header-anchor" href="#allow-stacking-with-other-discount-campaigns" aria-label="Permalink to &quot;Allow Stacking with Other Discount Campaigns&quot;">​</a></h3><p><img src="'+d+'" alt="Stacking with Campaigns"></p><p>Controls whether different <em>types</em> of CampaignBay campaigns can be applied together on the same cart.</p><ul><li><strong>Checked:</strong> Multiple active discount campaigns can apply to the same cart.</li><li><strong>Unchecked:</strong> Only the single best overall discount applies.</li></ul><div class="info custom-block"><p class="custom-block-title">Learn More</p><p>The order and logic for how campaigns are stacked is very specific.</p><p><strong><a href="./../core-concepts/understanding-the-engine.html#step-2-stacking-between-discount-groups">Read the Full Guide: The Discount Engine &amp; Stacking →</a></strong></p></div><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Continue exploring advanced data management and licensing options.</p><ul><li><strong><a href="./advanced-settings.html">Advanced Settings →</a></strong></li></ul>',31)]))}const x=e(l,[["render",h]]);export{b as __pageData,x as default};
